from itertools import permutations
def lin_ok(t, s=(0,0,-6,-6)):
    for perm in set(permutations(s)):
        d=[perm[i]-t[i] for i in range(4)]
        if sum(sorted(d)[:2]) >= -1e-9:
            return True, perm, d
    return False,None,None
def sort_state(v): return tuple(sorted(v, reverse=True))
def next_states_exact(state, step=0.5):
    r1,r2,r3,r4=state
    outs=[]
    def add(name,param,v):
        outs.append((name,param,sort_state(v)))
    # M1 snake original
    maxa=max(0,r2-r3)
    a=0
    while a<=maxa+1e-9:
        add("snake1",a,[r1,r2,r3+a,r4-a])
        a+=step
    # M2
    maxa=max(0,min(r1-r2,(r3-r4)/2))
    a=0
    while a<=maxa+1e-9:
        add("codim",a,[r1,r2+a,r3-a,r4+a])
        a+=step
    # M3 original
    maxa=max(0,min((r1-r2)/4,(r3-r4)/2))
    a=0
    while a<=maxa+1e-9:
        add("short_orig",a,[r1-a,r2+3*a,r3-a,r4+a])
        a+=step
    # M3 technical 1: to A R1, A^-3 R2, R3,R4, A^4<R2/R1 -> a<(r1-r2)/4
    maxa=max(0,(r1-r2)/4)
    a=0
    while a<=maxa+1e-9:
        add("short_preserve34",a,[r1-a,r2+3*a,r3,r4])
        a+=step
    # M3 technical 2: to A R1,A^-3R2,A_length,B, where stretch A length = eps^-a
    maxa=max(0,(r1-r2)/4)
    a=0
    while a<=maxa+1e-9:
        p=-a
        q=r3+r4-p  # product
        # condition R3 < A < sqrt: length, exponents r3 > p > (r3+r4)/2
        if r3 >= p-1e-9 and p >= (r3+r4)/2-1e-9:
            add("short_interp",a,[r1-a,r2+3*a,p,q])
        a+=step
    # M4 pinching
    # a exponent of A length, condition r1<a, 2a+b>r2+r3+r4
    vals=[x*step for x in range(int(-20/step), int(15/step)+1)]
    for aexp in vals:
        if aexp>=r1-1e-9: # A<=R1 length? R1>A means r1<a; allow eq
            for b in vals:
                if 2*aexp+b>=r2+r3+r4-1e-9:
                    add("pinch",(aexp,b),[aexp,aexp,aexp,b])
    # M5 double pinch
    for aexp in vals:
        if aexp<=r1+1e-9 and 2*aexp>=r2+r3-1e-9: # R1<A (r1>a), A^2<R2R3
            for b in vals:
                if 3*aexp+b>=r1+r2+r3+r4-1e-9:
                    add("double",(aexp,b),[2*r1-aexp,aexp,aexp,b])
    return outs

