import random, math, itertools, numpy as np, sys, time
def lin_margin(t, s=(0,0,-6,-6)):
    best=-1e9; bestdata=None
    for perm in set(permutations(s)):
        d=[perm[i]-t[i] for i in range(4)]
        margin=sum(sorted(d)[:2])
        if margin>best:
            best=margin; bestdata=(perm,d)
    return best,bestdata
def random_next(st):
    r1,r2,r3,r4=st
    moves=[]
    # choose a move type randomly
    typ=random.choice(["snake","codim","short_orig","short_preserve34","short_interp","pinch","double"])
    if typ=="snake":
        maxa=max(0,r2-r3); a=random.random()*maxa if maxa>0 else 0
        return typ,a,sort_state([r1,r2,r3+a,r4-a])
    if typ=="codim":
        maxa=max(0,min(r1-r2,(r3-r4)/2)); a=random.random()*maxa if maxa>0 else 0
        return typ,a,sort_state([r1,r2+a,r3-a,r4+a])
    if typ=="short_orig":
        maxa=max(0,min((r1-r2)/4,(r3-r4)/2)); a=random.random()*maxa if maxa>0 else 0
        return typ,a,sort_state([r1-a,r2+3*a,r3-a,r4+a])
    if typ=="short_preserve34":
        maxa=max(0,(r1-r2)/4); a=random.random()*maxa if maxa>0 else 0
        return typ,a,sort_state([r1-a,r2+3*a,r3,r4])
    if typ=="short_interp":
        maxa=max(0,(r1-r2)/4)
        # need p=-a between mid and r3: a between -r3 and -(mid)
        lo=max(0,-r3)
        hi=min(maxa,-(r3+r4)/2)
        if hi<lo:
            a=random.random()*maxa if maxa>0 else 0
            return "short_preserve34",a,sort_state([r1-a,r2+3*a,r3,r4])
        a=lo+random.random()*(hi-lo)
        p=-a; q=r3+r4-p
        return typ,a,sort_state([r1-a,r2+3*a,p,q])
    if typ=="pinch":
        # choose a between r1 and maybe max(r1, target range), b minimal often
        a=r1 + random.random()*max(1, (r2-r4) if r2>r4 else 5) # exponent bigger = smaller a length, can shrink
        # b minimal plus random
        bmin=r2+r3+r4-2*a
        b=bmin + random.random()*5
        return typ,(a,b),sort_state([a,a,a,b])
    if typ=="double":
        # conditions a<=r1, a>=(r2+r3)/2
        lo=(r2+r3)/2
        hi=r1
        if hi<lo:
            a=hi
        else:
            a=lo+random.random()*(hi-lo)
        bmin=r1+r2+r3+r4-3*a
        b=bmin+random.random()*5
        return typ,(a,b),sort_state([2*r1-a,a,a,b])

def random_search(ntrials=200000, depth=6):
    best=(-1e9,None,None)
    start=sort_state((1,-4,-5,-6))
    for tr in range(ntrials):
        st=start; path=[]
        for d in range(depth):
            name,param,st=random_next(st)
            path.append((name,param,st))
            margin,data=lin_margin(st)
            if margin>best[0]:
                best=(margin,path.copy(),data)
                if margin>-1:
                    print("best",best[0], "depth",d+1, "st",st, "data",data, "path",path)
            if margin>=0:
                print("FOUND",tr,d+1,st,data,path)
                return True,path,st,data
    print("best final",best[0], best[2])
    for m in best[1] or []: print(m)
    return False,best
