def ratios(initial, final):
    r=sort_state(initial); s=sort_state(final)
    # assume both sorted desc exponents
    x = r[0]-s[0]
    z = (r[2]+r[3])-(s[2]+s[3])
    w = sum(r)-(s[0]+0.5*s[1]+1.5*s[2]+s[3])
    return x,z,w
